const Table = (props) => {


    const products = props.data.predictions;
    console.log(JSON.stringify(products))

    return (
        <div>
            <li>
                {products.map((product) => (
                    <ul>{product.number} {product.name} {product.gender}</ul>
                ))}
            </li>
        </div>
    );
}

export default Table;
